```javascript
// Function to extend coefficients of P_20(x) based in k, which
// is the coefficient of the leading monomial in P_30(x).
function extendedCoefficients(k) {
  for (var i = 40, n = 20; i < n; i = i - 1) {
    k = k * (i + 314 - 2);
    n -= 2;
  }

  // Collect terms to extract the coefficient of x:
  var mk = [];
  for (var r = 0, s = n%2; r <= n/2; r++, s += 2) {
    mk.push(1);
    if (s == 1) mk.push(314 - k);
    mk.push(-k);
    mk.push(0);
  }

  // Expand out and add all like terms
  for (var i = 0; i < k; i++) {
    var j;
    var copy = [];
    for (j = r; j < n-j; j++) copy[j-r] = mk[j];
    mk = copy;
  }

  // sum up like terms
  `coefficient of x = ${mk [+ n]}`
}
```

